import {Link, Navigate, useNavigate} from "react-router-dom";
import {useRef, useState} from "react";
import axios from "axios";
import {useDispatch, useSelector} from "react-redux";
import {login} from "../actions/auth";

const required = (value) => {
    if (value) {
        return (
            <div className="alert alert-danger">
                This field is required!
            </div>
        )
    }
}
const LoginForm = (props) => {
    let navigate = useNavigate();

    const form = useRef();
    const checkBtn = useRef();

    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [loading, setLoading] = useState(false);


    const {isLoggedIn} = useSelector(state => state.auth);
    const {message} = useSelector(state => state.message);

    const dispatch = useDispatch();

    const onChangeUserName = (e) => {
        const email = e.target.value;
        setEmail(email);
    }

    const onChangePassword = (e) => {
        const password = e.target.value;
        setPassword(password);
    }
    const handleLogin = (e) => {
        e.preventDefault();

        setLoading(true);

        form.current.validateAll();

        if (checkBtn.current.context._error.length === 0){
            dispatch(login(formData.email, formData.password))
                .then(() => {
                    navigate("/")
                    window.location.reload();
                })
                .catch(() => {
                    setLoading(false)
                })
        }


    }
    if (isLoggedIn) {
        return <Navigate to={'/'}></Navigate>
    }
    return (
        <div className="container bg-dark p-5">
            <span> <Link to="/" className="text-decoration-none">Trang chủ </Link>
                <i className="bi bi-chevron-double-right"></i>
                <span className="text-warning"> Đăng nhập</span>
            </span>
            <form onSubmit={handleSubmit} className="container p-4">
                <h2 className="text-warning text-center">Đăng nhập</h2>
                <div className="mb-3 mt-3">
                    <label htmlFor="email">Email:</label>
                    <input
                        type="email"
                        className="form-control"
                        id="email"
                        placeholder="Enter email"
                        name="email"
                        onChange={handleChange}
                        value={formData.email}
                        required/>
                </div>
                <div className="mb-3">
                    <label htmlFor="pwd">Mật khẩu:</label>
                    <input
                        type="password"
                        className="form-control"
                        id="pwd"
                        placeholder="Enter password"
                        name="password"
                        value={formData.password}
                        onChange={handleChange}
                        required/>
                </div>
                <div className="form-check mb-3 text-end">
                    <label className="form-check-label me-3">
                        <Link className="text-decoration-none text-warning" to="/repassword">Quên mật khẩu </Link>
                    </label>
                    <label className="form-check-label">
                        <Link className="text-decoration-none text-warning" to="/register"> Đăng ký</Link>
                    </label>
                </div>
                <button type="submit" className="btn btn-outline-warning form-control mb-3">Đăng nhập</button>
                <button type="submit" className="btn btn-outline-danger form-control">Đăng nhập bằng tài khoản google
                </button>
            </form>
        </div>
    )
}

export default LoginForm;
